import React, { useState } from "react";

export default (props) => {
  const [input1, onChangeInput1] = useState('');
  const [input2, onChangeInput2] = useState('');
  const [input3, onChangeInput3] = useState('');
  const [input4, onChangeInput4] = useState('');
  const [input5, onChangeInput5] = useState('');

  return (
    <div className="min-h-screen flex justify-center items-start bg-gray-100 py-10 overflow-auto">
      {/* Container chính căn giữa */}
      <div className="flex flex-col items-start bg-white w-[1440px] rounded-[10px] shadow-lg p-5">
        
        {/* Header */}
        <div className="flex items-start self-stretch bg-[#88BCF8] py-[3px] mb-2 rounded-[10px]">
          <img
            src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"} 
            className="w-[142px] h-[129px] ml-[167px] mr-[338px] object-fill"
          />
          <input
            placeholder={"Nhập để tìm kiếm"}
            value={input1}
            onChange={(event)=>onChangeInput1(event.target.value)}
            className="text-black bg-[#F6FEFF] text-base w-[376px] py-[7px] pl-[51px] pr-[102px] mt-[61px] mb-10 mr-3 rounded-[50px] border-0"
          />
          <img
            src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qfk5vizv_expires_30_days.png"} 
            className="w-[60px] h-[45px] mt-[53px] mr-[63px] rounded-[10px] object-fill"
          />
          <div className="flex flex-col items-center w-[47px] relative mt-[38px] mr-1">
            <img
              src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/pt1vc4hr_expires_30_days.png"} 
              className="w-[47px] h-[69px] object-fill"
            />
            <img
              src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/rykqncqm_expires_30_days.png"} 
              className="w-[63px] h-[63px] absolute bottom-0 right-[35px] object-fill"
            />
          </div>
          <img
            src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/l63q73r0_expires_30_days.png"} 
            className="w-[42px] h-[42px] mt-[52px] mr-[188px] object-fill"
          />
        </div>

        {/* Body */}
        <div className="flex items-start mb-[50px] ml-[27px]">
          {/* Sidebar */}
          <div className="flex flex-col items-center bg-[#88BCF8] w-[88px] p-[23px] mt-[38px] mr-[65px] gap-[30px] rounded-[10px] border-2 border-solid border-[#00000000]">
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/od5pn9yq_expires_30_days.png"} className="w-[42px] h-[42px] object-fill"/>
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nxy76zef_expires_30_days.png"} className="w-[42px] h-[42px] object-fill"/>
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/8o6xqfxj_expires_30_days.png"} className="w-[42px] h-[37px] object-fill"/>
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/v47lki4u_expires_30_days.png"} className="w-[42px] h-[42px] object-fill"/>
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ebla58bn_expires_30_days.png"} className="w-[42px] h-[42px] object-fill"/>
          </div>

          {/* Main feed */}
          <div className="flex flex-col items-start w-[1260px] gap-2">
            {/* Bạn có thể giữ nguyên tất cả div con bên trong */}
            {/* ...copy tất cả nội dung hiện tại của bạn vào đây... */}
          </div>
        </div>
      </div>
    </div>
  )
}
